// The milestone-2 scene from Go, on the kaya bindings: kaya_wire.go
// (generated by kaya-bindgen from kaya::spec) carries the packers and
// parser, runtime.go the cgo and the direct-ring occurrence loop. What
// remains here is the scene declaration and the logic answering
// occurrences.
//
// Build the library first (cargo build), then, from the repo root
// (dev.kaya's go.mod lives there):
//     KAYA_SELFTEST=1 go run crates/kaya/examples/milestone2.go
package main

import (
	"fmt"
	"os"
	"runtime"

	kaya "dev.kaya/bindings/go"
)

func init() {
	// kaya.Run must own the process main thread.
	runtime.LockOSThread()
}

// Guest-allocated ids, counted from 1 per space.
const (
	sigStatus = 1
	sigExtras = 2
	wColumn   = 1
	wStep     = 2
	wStatus   = 3
	wWhen     = 4
	wGroups   = 5
	cGroups   = 1
	cItems    = 2
	nBanner   = 1
	nGroupCol = 2
	nGroupLbl = 3
	nItemsFor = 4
	nItemRow  = 5
	nItemText = 6
	nRemove   = 7
)

func buildScene() {
	kaya.Submit(
		kaya.TxCreateSignal(sigStatus, "step 0"),
		kaya.TxCreateSignal(sigExtras, false),
		kaya.TxCreateWidget(wColumn, kaya.KindColumn),
		kaya.TxCreateWidget(wStep, kaya.KindButton),
		kaya.TxSetText(wStep, "step"),
		kaya.TxCreateWidget(wStatus, kaya.KindLabel),
		kaya.TxBindText(wStatus, sigStatus),
		// When(extras): a banner label.
		kaya.TxCreateWhen(wWhen, sigExtras),
		kaya.TxCreateWidget(nBanner, kaya.KindLabel),
		kaya.TxSetText(nBanner, "extras on"),
		kaya.TxTemplateEnd(),
		// For over groups, nesting a For over items.
		kaya.TxCreateCollection(cGroups),
		kaya.TxCreateFor(wGroups, cGroups),
		kaya.TxCreateWidget(nGroupCol, kaya.KindColumn),
		kaya.TxCreateWidget(nGroupLbl, kaya.KindLabel),
		kaya.TxBindTextElement(nGroupLbl, 0),
		kaya.TxAddChild(nGroupCol, nGroupLbl),
		kaya.TxCreateCollection(cItems),
		kaya.TxCreateFor(nItemsFor, cItems),
		kaya.TxCreateWidget(nItemRow, kaya.KindColumn),
		kaya.TxCreateWidget(nItemText, kaya.KindLabel),
		kaya.TxBindTextElement(nItemText, 0),
		kaya.TxCreateWidget(nRemove, kaya.KindButton),
		kaya.TxSetText(nRemove, "remove"),
		kaya.TxAddChild(nItemRow, nItemText),
		kaya.TxAddChild(nItemRow, nRemove),
		kaya.TxTemplateEnd(),
		kaya.TxAddChild(nGroupCol, nItemsFor),
		kaya.TxTemplateEnd(),
		kaya.TxAddChild(wColumn, wStep),
		kaya.TxAddChild(wColumn, wStatus),
		kaya.TxAddChild(wColumn, wWhen),
		kaya.TxAddChild(wColumn, wGroups),
		kaya.TxMount(0, wColumn), // window 0: the default
	)
}

func app() {
	buildScene()
	steps := 0
	for {
		id, keys, ok := kaya.NextClick()
		if !ok {
			return // shutdown
		}
		if len(keys) == 0 && id == wStep {
			steps++
			var changes [][]byte
			switch steps {
			case 1:
				changes = [][]byte{
					kaya.TxCollectionInsert(cGroups, nil, "g1", "Work"),
					kaya.TxCollectionInsert(cItems, []any{"g1"}, "a", "send report"),
					kaya.TxCollectionInsert(cItems, []any{"g1"}, "b", "buy milk"),
				}
			case 2:
				changes = [][]byte{
					kaya.TxCollectionInsert(cGroups, nil, "g2", "Home"),
					kaya.TxCollectionInsert(cItems, []any{"g2"}, "a", "water plants"),
					kaya.TxCollectionUpdate(cGroups, nil, "g1", "Office"),
				}
			}
			changes = append(changes,
				kaya.TxWriteSignal(sigExtras, steps == 1),
				kaya.TxWriteSignal(sigStatus, fmt.Sprintf("step %d", steps)))
			kaya.Submit(changes...)
		} else if len(keys) == 2 && id == nRemove {
			group, item := keys[0].(string), keys[1].(string)
			kaya.Submit(
				kaya.TxCollectionRemove(cItems, []any{group}, item),
				kaya.TxWriteSignal(sigStatus, fmt.Sprintf("removed %s/%s", group, item)))
		}
	}
}

func main() {
	kaya.Init()
	done := make(chan struct{})
	go func() {
		app()
		close(done)
	}()
	code := kaya.Run() // takes over the main thread until the app exits
	<-done             // shutdown has been signalled; the drain loop ends
	os.Exit(code)
}
